1289	pub(crate) fn execute(state: &mut LuaState, mut ci: CallInfoIdx) -> Result<(), LuaError> {
1290	    let mut trap: bool;
1291	
1292	    // PORT NOTE: `startfunc:` is the entry point that (re)sets `trap`.
1293	    'startfunc: loop {
1294	        // C: startfunc: trap = L->hookmask;
1295	        trap = state.hook_mask() != 0;
1296	
1297	        // PORT NOTE: `returning:` is the re-entry after a Lua call returns.
1298	        // Re-enters 'returning without resetting trap.
1299	        'returning: loop {
1300	            // C: cl = ci_func(ci); k = cl->p->k; pc = ci->u.l.savedpc;
1301	            let cl = match state.ci_lua_closure(ci) {
1302	                Some(c) => c,
1303	                None => {
1304	                    return Err(LuaError::runtime(format_args!(
1305	                        "internal: execute called on non-Lua frame"
1306	                    )));
1307	                }
1308	            };
1309	            // pc is an index into proto.code (u32)
1310	            let mut pc: u32 = state.ci_savedpc(ci);
1311	
1312	            // C: if (l_unlikely(trap)) trap = luaG_tracecall(L);
1313	            if trap {
1314	                trap = state.trace_call(ci)?;
1315	            }
1316	            // C: base = ci->func.p + 1;
1317	            let mut base: StackIdx = state.ci_base(ci);
1318	
1319	            // ── Main dispatch loop ──────────────────────────────────────────
1320	            // C: for (;;) { Instruction i; vmfetch(); vmdispatch(GET_OPCODE(i)) {...} }
1321	            'dispatch: loop {
1322	                // C: vmfetch() — handle hooks, then fetch+advance pc
1323	                if trap {
1324	                    // C: trap = luaG_traceexec(L, pc); updatebase(ci);
1325	                    trap = state.trace_exec(ci, pc)?;
1326	                    base = state.ci_base(ci); // updatebase
1327	                }
1328	                let i: Instruction = state.proto_code(&cl, pc);
1329	                pc += 1;
1330	
1331	                debug_assert!(base == state.ci_base(ci));
1332	
1333	                // C: vmdispatch(GET_OPCODE(i))
1334	                match i.opcode() {
1335	                    // ── OP_MOVE ──────────────────────────────────────────────
1336	                    // C: StkId ra = RA(i); setobjs2s(L, ra, RB(i));
1337	                    OpCode::Move => {
1338	                        let ra = base + i.arg_a();
1339	                        let rb = base + i.arg_b();
1340	                        let v = state.get_at(rb).clone();
1341	                        state.set_at(ra, v);
1342	                    }
1343	                    // ── OP_LOADI ─────────────────────────────────────────────
1344	                    // C: lua_Integer b = GETARG_sBx(i); setivalue(s2v(ra), b);
1345	                    OpCode::LoadI => {
1346	                        let ra = base + i.arg_a();
1347	                        let b = i.arg_s_bx() as i64;
1348	                        state.set_at(ra, LuaValue::Int(b));
1349	                    }
1350	                    // ── OP_LOADF ─────────────────────────────────────────────
1351	                    // C: int b = GETARG_sBx(i); setfltvalue(s2v(ra), cast_num(b));
1352	                    OpCode::LoadF => {
1353	                        let ra = base + i.arg_a();
1354	                        let b = i.arg_s_bx() as f64;
1355	                        state.set_at(ra, LuaValue::Float(b));
1356	                    }
1357	                    // ── OP_LOADK ─────────────────────────────────────────────
1358	                    // C: TValue *rb = k + GETARG_Bx(i); setobj2s(L, ra, rb);
1359	                    OpCode::LoadK => {
1360	                        let ra = base + i.arg_a();
1361	                        let k_idx = i.arg_bx() as usize;
1362	                        let v = state.proto_const(&cl, k_idx).clone();
1363	                        state.set_at(ra, v);
1364	                    }
1365	                    // ── OP_LOADKX ────────────────────────────────────────────
1366	                    // C: rb = k + GETARG_Ax(*pc); pc++;
1367	                    OpCode::LoadKX => {
1368	                        let ra = base + i.arg_a();
1369	                        let extra = state.proto_code(&cl, pc);
1370	                        pc += 1;
1371	                        let k_idx = extra.arg_ax() as usize;
1372	                        let v = state.proto_const(&cl, k_idx).clone();
1373	                        state.set_at(ra, v);
1374	                    }
1375	                    // ── OP_LOADFALSE ─────────────────────────────────────────
1376	                    OpCode::LoadFalse => {
1377	                        let ra = base + i.arg_a();
1378	                        state.set_at(ra, LuaValue::Bool(false));
1379	                    }
1380	                    // ── OP_LFALSESKIP ────────────────────────────────────────
1381	                    // C: setbfvalue(s2v(ra)); pc++; (skip next instruction)
1382	                    OpCode::LFalseSkip => {
1383	                        let ra = base + i.arg_a();
1384	                        state.set_at(ra, LuaValue::Bool(false));
1385	                        pc += 1;
1386	                    }
1387	                    // ── OP_LOADTRUE ──────────────────────────────────────────
1388	                    OpCode::LoadTrue => {
1389	                        let ra = base + i.arg_a();
1390	                        state.set_at(ra, LuaValue::Bool(true));
1391	                    }
1392	                    // ── OP_LOADNIL ───────────────────────────────────────────
1393	                    // C: int b = GETARG_B(i); do { setnilvalue(s2v(ra++)); } while (b--);
1394	                    OpCode::LoadNil => {
1395	                        let ra = base + i.arg_a();
1396	                        let b = i.arg_b();
1397	                        for k in 0..=b {
1398	                            state.set_at(ra + k, LuaValue::Nil);
1399	                        }
